package entities;

import java.time.LocalDateTime;
import java.util.ArrayList;
import java.util.List;

public class Musique {
    private Integer id;
    private String genre;
    private String audio;
    private LocalDateTime updatedAt;

    // Relation many-to-many via playlist_musique (loaded by service layer).
    private List<Playlist> playlists = new ArrayList<>();

    public Musique() {
    }

    public Integer getId() {
        return id;
    }

    public void setId(Integer id) {
        this.id = id;
    }

    public String getGenre() {
        return genre;
    }

    public void setGenre(String genre) {
        this.genre = genre;
    }

    public String getAudio() {
        return audio;
    }

    public void setAudio(String audio) {
        this.audio = audio;
    }

    public LocalDateTime getUpdatedAt() {
        return updatedAt;
    }

    public void setUpdatedAt(LocalDateTime updatedAt) {
        this.updatedAt = updatedAt;
    }

    public List<Playlist> getPlaylists() {
        return playlists;
    }

    public void setPlaylists(List<Playlist> playlists) {
        this.playlists = playlists != null ? playlists : new ArrayList<>();
    }
}

package entities;

import java.time.LocalDateTime;
import java.util.ArrayList;
import java.util.List;

public class Musique extends Oeuvre {
    private String genre;
    private String audio;
    private LocalDateTime updatedAt;

    // Relation many-to-many via playlist_musique (loaded by service layer).
    private List<Playlist> playlists = new ArrayList<>();

    public Musique() {
        super();
        setClasse("musique");
    }

    public String getGenre() {
        return genre;
    }

    public void setGenre(String genre) {
        this.genre = genre;
    }

    public String getAudio() {
        return audio;
    }

    public void setAudio(String audio) {
        this.audio = audio;
    }

    public LocalDateTime getUpdatedAt() {
        return updatedAt;
    }

    public void setUpdatedAt(LocalDateTime updatedAt) {
        this.updatedAt = updatedAt;
    }

    public List<Playlist> getPlaylists() {
        return playlists;
    }

    public void setPlaylists(List<Playlist> playlists) {
        this.playlists = playlists != null ? playlists : new ArrayList<>();
    }
}

package entities;

import java.time.LocalDate;
import java.time.LocalDateTime;

public class Personne {
    private Integer id;
    private String photoProfil;
    private String resetToken;
    private LocalDateTime resetTokenExpires;
    private String nom;
    private String prenom;
    private LocalDate dateNaissance;
    private String email;
    private String mdp;
    private String role;
    private String statut;
    private LocalDate dateInscription;
    private String numTel;
    private String ville;
    private String biographie;
    private String specialite;
    private String centreInteret;
    private String photoReferencePath;

    // Legacy field kept for compatibility with existing ServicePersonne.
    private Integer age;

    public Personne() {
    }

    public Personne(String nom, String prenom, Integer age) {
        this.nom = nom;
        this.prenom = prenom;
        this.age = age;
    }

    public Integer getId() {
        return id;
    }

    public void setId(Integer id) {
        this.id = id;
    }

    public String getPhotoProfil() {
        return photoProfil;
    }

    public void setPhotoProfil(String photoProfil) {
        this.photoProfil = photoProfil;
    }

    public String getResetToken() {
        return resetToken;
    }

    public void setResetToken(String resetToken) {
        this.resetToken = resetToken;
    }

    public LocalDateTime getResetTokenExpires() {
        return resetTokenExpires;
    }

    public void setResetTokenExpires(LocalDateTime resetTokenExpires) {
        this.resetTokenExpires = resetTokenExpires;
    }

    public String getNom() {
        return nom;
    }

    public void setNom(String nom) {
        this.nom = nom;
    }

    public String getPrenom() {
        return prenom;
    }

    public void setPrenom(String prenom) {
        this.prenom = prenom;
    }

    public LocalDate getDateNaissance() {
        return dateNaissance;
    }

    public void setDateNaissance(LocalDate dateNaissance) {
        this.dateNaissance = dateNaissance;
    }

    public String getEmail() {
        return email;
    }

    public void setEmail(String email) {
        this.email = email;
    }

    public String getMdp() {
        return mdp;
    }

    public void setMdp(String mdp) {
        this.mdp = mdp;
    }

    public String getRole() {
        return role;
    }

    public void setRole(String role) {
        this.role = role;
    }

    public String getStatut() {
        return statut;
    }

    public void setStatut(String statut) {
        this.statut = statut;
    }

    public LocalDate getDateInscription() {
        return dateInscription;
    }

    public void setDateInscription(LocalDate dateInscription) {
        this.dateInscription = dateInscription;
    }

    public String getNumTel() {
        return numTel;
    }

    public void setNumTel(String numTel) {
        this.numTel = numTel;
    }

    public String getVille() {
        return ville;
    }

    public void setVille(String ville) {
        this.ville = ville;
    }

    public String getBiographie() {
        return biographie;
    }

    public void setBiographie(String biographie) {
        this.biographie = biographie;
    }

    public String getSpecialite() {
        return specialite;
    }

    public void setSpecialite(String specialite) {
        this.specialite = specialite;
    }

    public String getCentreInteret() {
        return centreInteret;
    }

    public void setCentreInteret(String centreInteret) {
        this.centreInteret = centreInteret;
    }

    public String getPhotoReferencePath() {
        return photoReferencePath;
    }

    public void setPhotoReferencePath(String photoReferencePath) {
        this.photoReferencePath = photoReferencePath;
    }

    public Integer getAge() {
        return age;
    }

    public void setAge(Integer age) {
        this.age = age;
    }

    @Override
    public String toString() {
        return "Personne{" +
                "id=" + id +
                ", nom='" + nom + '\'' +
                ", prenom='" + prenom + '\'' +
                ", email='" + email + '\'' +
                ", role='" + role + '\'' +
                ", statut='" + statut + '\'' +
                '}';
    }
}

/* Base */
.auth-root {
	-fx-font-family: "Segoe UI", "Inter", "Arial";
	-fx-background-color: linear-gradient(to bottom right, #e6eeff 0%, #eef4ff 40%, #e7f1ff 100%);
}

.auth-landing-shell,
.auth-signup-shell {
	-fx-padding: 24;
}

.auth-card,
.auth-landing-card {
	-fx-background-color: rgba(255, 255, 255, 0.9);
	-fx-background-radius: 24;
	-fx-border-radius: 24;
	-fx-border-color: rgba(148, 163, 184, 0.2);
	-fx-border-width: 1;
	-fx-effect: dropshadow(gaussian, rgba(30, 41, 59, 0.18), 30, 0.2, 0, 14);
}

/* Top bar */
.auth-topbar {
	-fx-background-color: rgba(255, 255, 255, 0.88);
	-fx-border-color: rgba(99, 102, 241, 0.12);
	-fx-border-width: 0 0 1 0;
}

.auth-topbar-glass {
	-fx-background-color: rgba(255, 255, 255, 0.74);
	-fx-border-color: rgba(148, 163, 184, 0.2);
	-fx-effect: dropshadow(gaussian, rgba(15, 23, 42, 0.12), 18, 0.12, 0, 4);
}

.auth-mini-logo-wrap {
	-fx-background-color: rgba(79, 70, 229, 0.14);
	-fx-padding: 6 10;
	-fx-background-radius: 999;
	-fx-border-radius: 999;
	-fx-border-color: rgba(79, 70, 229, 0.22);
}

.auth-mini-logo {
	-fx-effect: dropshadow(gaussian, rgba(15, 23, 42, 0.2), 10, 0.14, 0, 2);
}

.auth-brand-mini,
.auth-brand {
	-fx-text-fill: #243b7a;
	-fx-font-weight: 800;
}

.auth-brand-mini {
	-fx-font-size: 19px;
}

.auth-topbar-link,
.auth-topbar-ghost,
.auth-topbar-primary {
	-fx-background-radius: 999;
	-fx-padding: 9 16;
	-fx-font-weight: 700;
	-fx-cursor: hand;
}

.auth-topbar-link {
	-fx-background-color: transparent;
	-fx-text-fill: #334155;
}

.auth-topbar-ghost {
	-fx-background-color: transparent;
	-fx-text-fill: #4f46e5;
	-fx-border-color: #c7d2fe;
	-fx-border-radius: 999;
	-fx-border-width: 1;
}

.auth-topbar-primary,
.auth-primary-button {
	-fx-background-color: linear-gradient(to right, #1fc4d7, #4f7cff);
	-fx-text-fill: white;
	-fx-background-radius: 14;
	-fx-font-weight: 700;
	-fx-padding: 12 20;
	-fx-cursor: hand;
	-fx-effect: dropshadow(gaussian, rgba(37, 99, 235, 0.3), 18, 0.22, 0, 5);
}

.auth-topbar-primary:hover,
.auth-primary-button:hover {
	-fx-background-color: linear-gradient(to right, #10bcd2, #3f6cf0);
}

.auth-primary-button:pressed,
.auth-topbar-primary:pressed {
	-fx-background-color: linear-gradient(to right, #0ea5b7, #345bd6);
}

/* Landing hero */

.auth-landing-shell-fluid {
	-fx-padding: 30;
}

.auth-landing-card-fluid {
	-fx-background-color: rgba(255, 255, 255, 0.88);
	-fx-background-radius: 30;
	-fx-border-radius: 30;
	-fx-border-color: rgba(148, 163, 184, 0.22);
	-fx-border-width: 1;
	-fx-effect: dropshadow(gaussian, rgba(15, 23, 42, 0.2), 38, 0.22, 0, 14);
}

.auth-landing-hero,
.auth-signup-hero {
	-fx-background-color: linear-gradient(to bottom right, #273c95 0%, #5164d9 60%, #7382ff 100%);
	-fx-background-radius: 24 0 0 24;
}

.auth-landing-hero-fluid {
	-fx-background-color: linear-gradient(to bottom right, #1d4ed8 0%, #2563eb 45%, #38bdf8 100%);
	-fx-background-radius: 30 0 0 30;
}

.auth-hero-logo-wrap {
	-fx-background-color: rgba(255, 255, 255, 0.16);
	-fx-padding: 14 18;
	-fx-background-radius: 22;
	-fx-border-radius: 22;
	-fx-border-color: rgba(255, 255, 255, 0.26);
}

.auth-hero-logo {
	-fx-effect: dropshadow(gaussian, rgba(15, 23, 42, 0.2), 18, 0.16, 0, 6);
}

.auth-landing-title {
	-fx-font-size: 42px;
	-fx-font-weight: 900;
	-fx-text-fill: #ffffff;
}

.auth-landing-text {
	-fx-font-size: 15px;
	-fx-text-fill: rgba(255, 255, 255, 0.92);
	-fx-line-spacing: 0.55em;
}

.auth-panel-block {
	-fx-spacing: 16;
}

.auth-landing-panel,
.auth-signup-card {
	-fx-background-radius: 0 24 24 0;
}

.auth-login-shell {
	-fx-padding: 24;
}

.auth-login-card {
	-fx-background-radius: 0 24 24 0;
}

.auth-login-card-fluid {
	-fx-background-color: linear-gradient(to bottom right, rgba(255, 255, 255, 0.94), rgba(241, 247, 255, 0.94));
	-fx-background-radius: 0 30 30 0;
	-fx-border-color: rgba(148, 163, 184, 0.2);
	-fx-border-width: 1;
	-fx-effect: dropshadow(gaussian, rgba(15, 23, 42, 0.16), 32, 0.2, 0, 12);
}

.auth-login-title {
	-fx-font-size: 32px;
}

.auth-login-subtitle {
	-fx-text-fill: #475569;
}

.auth-login-actions {
	-fx-padding: 4 0 0 0;
}

.auth-login-footer {
	-fx-padding: 2 0 0 0;
}

.auth-remember-checkbox {
	-fx-text-fill: #475569;
	-fx-font-weight: 600;
}

.auth-remember-checkbox .box {
	-fx-background-color: white;
	-fx-border-color: #cbd5e1;
	-fx-border-radius: 5;
	-fx-background-radius: 5;
}

.auth-landing-panel-fluid {
	-fx-background-color: linear-gradient(to bottom right, rgba(255, 255, 255, 0.92), rgba(241, 245, 255, 0.92));
	-fx-background-radius: 0 30 30 0;
}

.auth-landing-panel-title {
	-fx-font-size: 34px;
	-fx-font-weight: 800;
	-fx-text-fill: #0f172a;
}

.auth-landing-panel-text {
	-fx-font-size: 14px;
	-fx-text-fill: #475569;
	-fx-line-spacing: 0.5em;
}

.auth-hero-title,
.auth-title {
	-fx-text-fill: #ffffff;
	-fx-font-size: 32px;
	-fx-font-weight: 800;
	-fx-line-spacing: 0.2em;
}

.auth-hero-text,
.auth-subtitle,
.auth-panel-text,
.auth-helper-text,
.auth-message {
	-fx-font-size: 13px;
	-fx-line-spacing: 0.5em;
}

.auth-hero-text,
.auth-panel-text,
.auth-helper-text {
	-fx-text-fill: #667085;
}

.auth-panel-kicker,
.auth-section-title {
	-fx-text-fill: #4f46e5;
	-fx-font-size: 13px;
	-fx-font-weight: 800;
}

.auth-panel-title,
.auth-title {
	-fx-text-fill: #111827;
}

.auth-chip-row {
	-fx-padding: 2 0 0 0;
}

.auth-chip {
	-fx-background-color: rgba(255, 255, 255, 0.32);
	-fx-text-fill: #0f2454;
	-fx-background-radius: 999;
	-fx-padding: 8 14;
	-fx-font-size: 12px;
	-fx-font-weight: 700;
	-fx-border-color: rgba(255, 255, 255, 0.45);
	-fx-border-width: 1;
	-fx-border-radius: 999;
}

/* Form */
.auth-stepper {
	-fx-padding: 2 0 4 0;
}

.auth-step-badge {
	-fx-min-width: 34;
	-fx-min-height: 34;
	-fx-alignment: center;
	-fx-background-color: #e5e7eb;
	-fx-text-fill: #6b7280;
	-fx-font-weight: 800;
	-fx-background-radius: 999;
}

.auth-step-badge.active {
	-fx-background-color: #4f46e5;
	-fx-text-fill: white;
}

.auth-step-badge.done {
	-fx-background-color: #22c55e;
	-fx-text-fill: white;
}

.auth-field-label {
	-fx-text-fill: #334155;
	-fx-font-size: 13px;
	-fx-font-weight: 700;
}

.auth-input {
	-fx-background-color: rgba(255, 255, 255, 0.96);
	-fx-background-radius: 22;
	-fx-border-radius: 22;
	-fx-border-color: #cbd5e1;
	-fx-border-width: 1;
	-fx-padding: 12 14;
	-fx-font-size: 14px;
}

.combo-box-base.auth-input {
	-fx-background-color: white;
	-fx-background-radius: 22;
	-fx-border-radius: 22;
	-fx-border-color: #cbd5e1;
	-fx-border-width: 1;
	-fx-font-size: 14px;
}

.combo-box-base.auth-input:focused {
	-fx-border-color: #4f46e5;
	-fx-effect: dropshadow(gaussian, rgba(79, 70, 229, 0.18), 14, 0.15, 0, 0);
}

.combo-box-base.auth-input > .list-cell {
	-fx-padding: 11 14;
}

.auth-input:focused {
	-fx-border-color: #3b82f6;
	-fx-effect: dropshadow(gaussian, rgba(59, 130, 246, 0.2), 16, 0.16, 0, 0);
}

.auth-textarea {
	-fx-pref-row-count: 4;
}

.auth-role-toggle,
.auth-secondary-button,
.auth-link-button {
	-fx-cursor: hand;
}

.auth-role-toggle {
	-fx-background-color: #eef4ff;
	-fx-text-fill: #334155;
	-fx-background-radius: 999;
	-fx-border-radius: 999;
	-fx-border-color: #dbe7ff;
	-fx-border-width: 1;
	-fx-font-weight: 700;
	-fx-padding: 10 16;
}

.auth-role-toggle:selected {
	-fx-background-color: linear-gradient(to right, #2f6cf4, #4f46e5);
	-fx-text-fill: white;
}

.auth-secondary-button {
	-fx-background-color: rgba(255, 255, 255, 0.72);
	-fx-text-fill: #334155;
	-fx-font-weight: 700;
	-fx-background-radius: 14;
	-fx-border-color: #bfccff;
	-fx-border-width: 1.2;
	-fx-border-radius: 14;
	-fx-padding: 12 18;
}

.auth-secondary-button:hover,
.auth-topbar-link:hover,
.auth-link-button:hover {
	-fx-background-color: #eef2ff;
}

.auth-link-button {
	-fx-background-color: transparent;
	-fx-text-fill: #365fd9;
	-fx-font-weight: 700;
	-fx-padding: 0;
}

.auth-photo-preview {
	-fx-min-width: 150;
	-fx-min-height: 150;
	-fx-background-color: #cbd5e1;
	-fx-background-radius: 18;
	-fx-border-radius: 18;
	-fx-border-color: rgba(255,255,255,0.55);
	-fx-border-width: 1;
}

.auth-photo-placeholder {
	-fx-text-fill: white;
	-fx-font-weight: 700;
	-fx-opacity: 0.85;
}

.auth-message {
	-fx-min-height: 20;
	-fx-font-weight: 600;
}

.auth-message.error {
	-fx-text-fill: #dc2626;
}

.auth-message.success {
	-fx-text-fill: #16a34a;
}

.auth-or-divider {
	-fx-alignment: center;
	-fx-spacing: 10;
	-fx-padding: 2 0;
}

.auth-or-line {
	-fx-background-color: rgba(148, 163, 184, 0.45);
	-fx-pref-height: 1;
	-fx-max-height: 1;
}

.auth-or-label {
	-fx-text-fill: #64748b;
	-fx-font-size: 12px;
	-fx-font-weight: 700;
	-fx-padding: 0 4;
}

.auth-alt-actions {
	-fx-spacing: 10;
}

.auth-alt-button {
	-fx-background-radius: 16;
	-fx-text-fill: white;
	-fx-font-weight: 800;
	-fx-cursor: hand;
	-fx-padding: 12 18;
	-fx-effect: dropshadow(gaussian, rgba(15, 23, 42, 0.2), 14, 0.16, 0, 4);
}

.auth-alt-button.is-faceid {
	-fx-background-color: linear-gradient(to right, #5b6def, #7c3aed);
}

.auth-alt-button.is-qr {
	-fx-background-color: linear-gradient(to right, #ff9f1c, #ff7a18);
}

.auth-alt-button.is-fingerprint {
	-fx-background-color: linear-gradient(to right, #22c55e, #14b8a6);
}

.auth-alt-button:hover {
	-fx-opacity: 0.92;
}

.auth-alt-button:pressed {
	-fx-opacity: 0.84;
}

.auth-login-links {
	-fx-alignment: center;
	-fx-spacing: 6;
}

.auth-login-links .label {
	-fx-text-fill: #64748b;
	-fx-font-size: 13px;
}

.auth-input,
.combo-box-base.auth-input,
.text-area.auth-input {
	-fx-prompt-text-fill: #8aa0c7;
}

.auth-root.dark-mode {
	-fx-background-color: linear-gradient(to bottom right, #0f172a 0%, #111827 52%, #1e293b 100%);
}

.auth-root.dark-mode .auth-card,
.auth-root.dark-mode .auth-landing-card,
.auth-root.dark-mode .auth-signup-card,
.auth-root.dark-mode .auth-login-card-fluid,
.auth-root.dark-mode .auth-landing-panel-fluid {
	-fx-background-color: rgba(17, 24, 39, 0.78);
	-fx-border-color: rgba(148, 163, 184, 0.2);
}

.auth-root.dark-mode .auth-panel-title,
.auth-root.dark-mode .auth-login-title,
.auth-root.dark-mode .auth-field-label {
	-fx-text-fill: #e2e8f0;
}

.auth-root.dark-mode .auth-panel-text,
.auth-root.dark-mode .auth-subtitle,
.auth-root.dark-mode .auth-helper-text,
.auth-root.dark-mode .auth-login-links .label {
	-fx-text-fill: #94a3b8;
}

.auth-signup-card {
	-fx-background-color: rgba(255, 255, 255, 0.94);
	-fx-border-color: rgba(148, 163, 184, 0.2);
	-fx-border-width: 1;
}

.auth-scroll,
.auth-scroll > .viewport {
	-fx-background-color: transparent;
}

